\title{
SubQ-1.1-Small Technical Report
}

\footnotetext{
*Equal contribution.
}

\begin{figure}
\includegraphics[alt={},max width=\textwidth]{https://cdn.mathpix.com/cropped/d1d64d97-1678-4cd8-a2b9-48ee4ea54423-03.jpg?height=691&width=1073&top_left_y=962&top_left_x=524}
\captionsetup{labelformat=empty}
\caption{Figure 1: Relationship between the attention regime and experimentation. Dense attention makes long-context training expensive, limiting the number and scale of experiments that can be performed. SSA reduces those costs, enabling broader experimentation and the findings reported in this work.}
\end{figure}

\begin{figure}
\includegraphics[alt={},max width=\textwidth]{https://cdn.mathpix.com/cropped/d1d64d97-1678-4cd8-a2b9-48ee4ea54423-04.jpg?height=486&width=1309&top_left_y=247&top_left_x=408}
\captionsetup{labelformat=empty}
\caption{Figure 2: A taxonomy of approaches to long-context modeling. Architectural approaches change how the model itself processes a sequence; system-level approaches leave the model fixed and orchestrate around its context limit. SSA is a learned, content-dependent sparse-attention method, placed alongside the closest published comparison point.}
\end{figure}

\begin{figure}
\includegraphics[alt={},max width=\textwidth]{https://cdn.mathpix.com/cropped/d1d64d97-1678-4cd8-a2b9-48ee4ea54423-05.jpg?height=631&width=1123&top_left_y=259&top_left_x=500}
\captionsetup{labelformat=empty}
\caption{Figure 3: Dense attention operations per layer as a function of sequence length, shown across SubQ-1.1-Small's operating range. At 128 K tokens, a length many systems still treat as long context, attention requires only 8.6 billion operations per layer; at \(1 \mathrm{M}, 549\) billion; at \(2 \mathrm{M}, 2.2\) trillion, a fourfold increase for a doubling of context. Flash Attention preserves this quadratic growth in compute even as it reduces the memory footprint.}
\end{figure}

\begin{figure}
\includegraphics[alt={},max width=\textwidth]{https://cdn.mathpix.com/cropped/d1d64d97-1678-4cd8-a2b9-48ee4ea54423-08.jpg?height=596&width=1256&top_left_y=739&top_left_x=433}
\captionsetup{labelformat=empty}
\caption{Figure 4: The long-context tradeoff. Each row is a family of approaches; each column is one of the four properties a complete solution must provide. Every prior family leaves at least one column unmet or only partially met, the recurring pattern that motivates this work. SSA targets all four at once.}
\end{figure}

\begin{figure}
\includegraphics[alt={},max width=\textwidth]{https://cdn.mathpix.com/cropped/d1d64d97-1678-4cd8-a2b9-48ee4ea54423-10.jpg?height=79&width=1275&top_left_y=244&top_left_x=425}
\captionsetup{labelformat=empty}
\caption{Figure 5: Staged context-window extension with continued pretraining. The donor model began with a 262 K -token context window. YaRN positional scaling was re-applied at each stage ( \(262 \mathrm{~K}, 512 \mathrm{~K}\), 1 M , and 2 M ), with long-context continued pretraining performed between extensions. Most CPT tokens were trained at the 1 M stage, followed by a final extension and training stage at 2 M tokens.}
\end{figure}

\begin{figure}
\includegraphics[alt={},max width=\textwidth]{https://cdn.mathpix.com/cropped/d1d64d97-1678-4cd8-a2b9-48ee4ea54423-11.jpg?height=76&width=1378&top_left_y=408&top_left_x=373}
\captionsetup{labelformat=empty}
\caption{Figure 6: Memory-scaling ladder used during development. As context length increased, training progressively escalated from a single-node configuration to sequence parallelism, CPU offloading, multi-node sequence parallelism, nested offloading, and finally Ring Attention. Most experiments were run on the lowest rung capable of supporting the target context length, minimizing system complexity while preserving rapid iteration.}
\end{figure}

\begin{figure}
\includegraphics[alt={},max width=\textwidth]{https://cdn.mathpix.com/cropped/d1d64d97-1678-4cd8-a2b9-48ee4ea54423-12.jpg?height=624&width=1165&top_left_y=251&top_left_x=481}
\captionsetup{labelformat=empty}
\caption{Figure 7: SubQ-1.1-Small long-context retrieval. Single-needle NIAH accuracy is perfect ( \(100 \%\) ) at \(1 \mathrm{M}, 2 \mathrm{M}, 6 \mathrm{M}\), and 12 M tokens; RULER at 128 K is near-saturated at \(99.12 \%\).}
\end{figure}

\begin{figure}
\includegraphics[alt={},max width=\textwidth]{https://cdn.mathpix.com/cropped/d1d64d97-1678-4cd8-a2b9-48ee4ea54423-13.jpg?height=859&width=1150&top_left_y=257&top_left_x=485}
\captionsetup{labelformat=empty}
\caption{Figure 8: Knowledge capability on GPQA Diamond (pass@1). SubQ-1.1-Small (85.4\%) sits just below the mid-tier frontier models (Sonnet 4.6 and GPT-5.4-mini at \(87.5 \%\) ) and well above the smaller tiers (GPT-5.4-nano 81.7\%, Haiku 4.5 67.2\%).}
\end{figure}

\begin{figure}
\includegraphics[alt={},max width=\textwidth]{https://cdn.mathpix.com/cropped/d1d64d97-1678-4cd8-a2b9-48ee4ea54423-14.jpg?height=992&width=1084&top_left_y=257&top_left_x=519}
\captionsetup{labelformat=empty}
\caption{Figure 9: Coding capability. SubQ-1.1-Small reaches \(89.7 \%\) on LiveCodeBench (pass @ 4, originalpaper protocol), confirming that coding behavior was reintroduced after long-context optimization.}
\end{figure}

\begin{figure}
\includegraphics[alt={},max width=\textwidth]{https://cdn.mathpix.com/cropped/d1d64d97-1678-4cd8-a2b9-48ee4ea54423-15.jpg?height=715&width=1086&top_left_y=259&top_left_x=519}
\captionsetup{labelformat=empty}
\caption{Figure 10: AutomationBench Finance scores on long-horizon agentic finance tasks. SubQ-1.1-Small ( \(13 \%\) ) sits close to the absolute frontier (Opus \(4.816 \%\), GPT-5.5 18.0\%) and ahead of the medium and small models from Anthropic and OpenAI (Sonnet \(4.68 \%\), Haiku \(4.53 \%\), GPT-5.4-Mini 0.0\%).}
\end{figure}

