\begin{figure}
\includegraphics[alt={},max width=\textwidth]{https://cdn.mathpix.com/cropped/d1d64d97-1678-4cd8-a2b9-48ee4ea54423-16.jpg?height=635&width=1082&top_left_y=264&top_left_x=519}
\captionsetup{labelformat=empty}
\caption{Figure 11: SSA compute on a single B200. Attention-mechanism FLOPs per forward pass: dense attention grows quadratically while SSA grows linearly, a \(64 \times\) reduction at 1 M tokens.}
\end{figure}

\begin{figure}
\includegraphics[alt={},max width=\textwidth]{https://cdn.mathpix.com/cropped/d1d64d97-1678-4cd8-a2b9-48ee4ea54423-16.jpg?height=671&width=1146&top_left_y=1239&top_left_x=489}
\captionsetup{labelformat=empty}
\caption{Figure 12: Single-attention-layer SSA speedup over FlashAttention-2. SSA reaches parity near 16K tokens and pulls away as context grows, to \(56 \times\) at 1 M tokens, where SSA runs in 966 ms versus \(54,164 \mathrm{~ms}\) for FlashAttention-2. Measured on an H100.}
\end{figure}

